// Set long lived cookie expiration time in milliseconds (30 days)
const COOKIE_EXPIRATION = 2592000000;

function setCookie(username, passwordHash) {
    const cookieValue = JSON.stringify({ username, passwordHash });
    document.cookie = `remember_me=${cookieValue}; expires=${new Date(Date.now() + COOKIE_EXPIRATION).toUTCString()}`;
}

function getCookie() {
    let cookieValue = '';
    const cookies = document.cookie.split(';');
    for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim();
        if (cookie.startsWith('remember_me=')) {
            cookieValue = cookie.substring(12);
            break;
        }
    }
    return cookieValue ? JSON.parse(cookieValue) : null;
}

function autoLogin() {
    const rememberMeCookie = getCookie();
    if (rememberMeCookie) {
        const username = rememberMeCookie.username;
        const passwordHash = rememberMeCookie.passwordHash;
        // Call legacy login function or API with the stored credentials
        login(username, passwordHash);
    }
}

